const breadcrumbText = computed(() => {
  const path = findPathToDoc(currentDoc.value)
  if (!path?.length) return ''
  const titles = []
  const walk = (nodes, depth = 0) => {
    for (const n of nodes) {
      if (n.id === path[depth]) {
        titles.push(n.title)
        if (depth < path.length - 1 && n.children) walk(n.children, depth + 1)
        return true
      }
    }
    return false
  }
  walk(manualToc)
  if (currentLeaf.value) titles.push(currentLeaf.value.title)
  return titles.join(' / ')
})

